Handle out-of-order subagent messages using orphan buffering.

**Reference:** ~/src/happy/sources/sync/reducer/reducerTracer.ts

**Problem:**
When a subagent (Task tool) spawns, messages may arrive out of order:
1. Child sidechain message arrives
2. Parent Task tool call hasn't been processed yet
3. Child can't be linked to parent

**Solution - Orphan Buffering:**
```typescript
interface TracerState {
    taskTools: Map<string, { messageId: string; prompt: string }>;
    promptToTaskId: Map<string, string>;
    uuidToSidechainId: Map<string, string>;
    orphanMessages: Map<string, NormalizedMessage[]>;  // parentUuid -> children
    processedIds: Set<string>;
}

function processMessage(state: TracerState, msg: Message) {
    // If message has a parent reference
    if (msg.parentUuid) {
        const parentExists = state.processedIds.has(msg.parentUuid);

        if (\!parentExists) {
            // Buffer as orphan until parent arrives
            const orphans = state.orphanMessages.get(msg.parentUuid) || [];
            orphans.push(msg);
            state.orphanMessages.set(msg.parentUuid, orphans);
            return;
        }

        // Link to parent
        msg.sidechainId = state.uuidToSidechainId.get(msg.parentUuid);
    }

    // Process normally
    state.processedIds.add(msg.uuid);

    // Check if this message has orphaned children waiting
    const waitingOrphans = state.orphanMessages.get(msg.uuid);
    if (waitingOrphans) {
        state.orphanMessages.delete(msg.uuid);
        // Process orphans recursively (they now have their parent)
        for (const orphan of waitingOrphans) {
            processMessage(state, orphan);
        }
    }
}
```

**Integration:**
This runs in the daemon during sync and/or in web client's message reducer.
Ensures deeply nested subagents are properly linked.

