Add thin Zustand layer for UI state management.

**Reference:** ~/src/happy/sources/sync/storage.ts

**Why:**
Convex handles server state well, but we need local UI state for:
- Expanded/collapsed tool calls (persist across navigation)
- Collapsed sections in conversation list
- Search query and filter state
- Derived/computed data (grouped conversations)

**Implementation:**
```typescript
// packages/web/store/uiStore.ts
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

interface UIState {
    // Persisted state
    expandedToolCalls: Set<string>;
    collapsedSections: Set<string>;
    theme: 'light' | 'dark';

    // Session state
    searchQuery: string;
    activeFilter: 'my' | 'team';

    // Derived from Convex data (computed on apply)
    groupedConversations: ConversationGroup[] | null;

    // Actions
    toggleToolCall: (id: string) => void;
    toggleSection: (id: string) => void;
    setSearchQuery: (query: string) => void;
    setFilter: (filter: 'my' | 'team') => void;
    applyConversations: (convs: Conversation[]) => void;
}

export const useUIStore = create<UIState>()(
    persist(
        (set, get) => ({
            expandedToolCalls: new Set(),
            collapsedSections: new Set(),
            theme: 'dark',
            searchQuery: '',
            activeFilter: 'my',
            groupedConversations: null,

            toggleToolCall: (id) => set(state => {
                const next = new Set(state.expandedToolCalls);
                if (next.has(id)) next.delete(id);
                else next.add(id);
                return { expandedToolCalls: next };
            }),

            applyConversations: (convs) => set({
                groupedConversations: buildConversationGroups(convs),
            }),
        }),
        {
            name: 'codecast-ui',
            partialize: (state) => ({
                expandedToolCalls: Array.from(state.expandedToolCalls),
                collapsedSections: Array.from(state.collapsedSections),
                theme: state.theme,
            }),
        }
    )
);
```

**Shallow Selectors:**
```typescript
import { useShallow } from 'zustand/react/shallow';

function ConversationList() {
    const { grouped, filter } = useUIStore(useShallow(state => ({
        grouped: state.groupedConversations,
        filter: state.activeFilter,
    })));
    // Only re-renders when these specific values change
}
```

**Benefits:**
- Decouples UI state from Convex subscriptions
- Persist expand/collapse across page navigations
- Computed groupings avoid re-computing on every render
- Better performance with shallow selectors

